class Solution:
    def removeDuplicates(self, s: str) -> str:
        left, right = 0, 0
        seen = set()
        res = []
        while right < len(s):
            if s[right] in seen:
                left = max(left, right + 1)
                seen.clear()
            else:
                seen.add(s[right])
                res.append(s[right])
                if right == left:
                    res.extend(seen)
            right += 1
        return ''.join(res)

