class Solution {
public:
    std::string removeDuplicates(std::string s) {
        int left = 0, right = 0;
        std::set<char> seen;
        std::string res;
        while (right < s.length()) {
            if (seen.find(s[right]) != seen.end()) {
                left = std::max(left, right + 1);
                seen.clear();
            } else {
                seen.insert(s[right]);
                res += s[right];
                if (right == left) {
                    res += seen.begin(), seen.end();
                }
            }
            right++;
        }
        return res;
    }
};
